import type { Localized } from '../types'

/**
 * "Pièges d'examen" per concept sheet: recurring wrong-answer patterns and
 * the reflex that beats them. Merged into CONCEPTS by src/data/concepts.ts.
 */
export const CONCEPT_TRAPS: Record<string, Localized> = {
  // ─────────────────────────── PRINCIPLES ───────────────────────────
  'pr-stewardship': {
    fr: "• « Les usages locaux le permettent » ne justifie JAMAIS un cadeau ou paiement de facilitation : les réponses qui contournent l'éthique via un intermédiaire restent de la corruption.\n• Agir sur une simple rumeur de fraude est aussi faux que l'ignorer : le réflexe attendu est vérifier les faits, puis utiliser le canal de signalement officiel.\n• Un conflit d'intérêts se DÉCLARE avant d'influencer la décision — la réponse « rester discret car on se sait impartial » est un piège classique.\n• Attention aux options qui protègent l'entreprise en sacrifiant la transparence (cacher un défaut au client) : l'honnêteté prime sur la loyauté commerciale.\n• Influencer un auditeur pour requalifier une non-conformité en simple observation est une violation caractérisée — même si l'intention affichée est de « protéger le planning ».\n• Ne confondez pas discrétion professionnelle (respecter une confidence légitime) et complicité (couvrir une fraude) : le premier honore la parole donnée, le second la trahit.\n• Un cadeau « symbolique » offert par un fournisseur pendant un appel d'offres actif reste un problème d'équité, même sous le seuil de valeur autorisé — le contexte temporel compte autant que le montant.",
    en: "• “Local custom allows it” NEVER justifies a gift or facilitation payment: answers that route the bribe through an intermediary are still bribery.\n• Acting on a mere rumor of fraud is as wrong as ignoring it: the expected reflex is verify the facts, then use the official reporting channel.\n• A conflict of interest is DISCLOSED before it influences the decision — “stay quiet because you know you are impartial” is a classic trap.\n• Watch for options that protect the company by sacrificing transparency (hiding a defect from the customer): honesty outranks commercial loyalty.\n• Influencing an auditor to downgrade a non-conformity to a mere observation is a clear violation — even when framed as “protecting the schedule”.\n• Do not confuse professional discretion (honoring a legitimate confidence) with complicity (covering up fraud): the former keeps a promise, the latter betrays one.\n• A “symbolic” gift from a vendor during an active tender remains a fairness problem even under the allowed value threshold — timing matters as much as amount.",
  },
  'pr-team': {
    fr: "• Piège récurrent : une option où le chef de projet IMPOSE la charte ou les règles d'équipe. La bonne réponse les fait CO-CONSTRUIRE par l'équipe.\n• « Signaler le membre au responsable fonctionnel » apparaît souvent : c'est presque toujours faux tant qu'on n'a pas parlé à la personne d'abord.\n• La sécurité psychologique ne se décrète pas en réunion : méfiez-vous des réponses purement déclaratives (« rappeler que chacun peut s'exprimer »).\n• Une réponse qui contourne le problème d'équipe (réaffecter, séparer, isoler) traite le symptôme — elle n'est correcte qu'en dernier recours explicite.\n• Une équipe majoritairement introvertie ou distribuée n'a pas besoin d'être « corrigée » vers plus d'oral : diversifier les canaux de contribution (écrit asynchrone) bat forcer la prise de parole en réunion.\n• Le mentorat spontané entre pairs est une pratique saine et NE remplace PAS une formation structurée quand une compétence critique manque à toute l'équipe — les deux se combinent, ce n'est pas l'un ou l'autre.",
    en: "• Recurring trap: an option where the project manager IMPOSES the charter or ground rules. The right answer has the team CO-CREATE them.\n• “Report the member to their functional manager” appears often: it is almost always wrong until you have talked to the person first.\n• Psychological safety cannot be decreed in a meeting: beware purely declarative answers (“remind everyone they can speak up”).\n• An answer that routes around the team problem (reassign, separate, isolate) treats the symptom — it is only correct as an explicit last resort.\n• A mostly introverted or distributed team does not need “fixing” toward more talking: diversifying contribution channels (async writing) beats forcing meeting airtime.\n• Spontaneous peer mentoring is healthy practice and does NOT replace structured training when a critical skill is missing team-wide — the two combine, it is not either/or.",
  },
  'pr-stakeholders': {
    fr: "• Face à une partie prenante résistante, « l'exclure des réunions » ou « demander au sponsor de la recadrer » sont des distracteurs quasi systématiques : la bonne réponse commence par COMPRENDRE ses préoccupations.\n• « Toutes les parties prenantes reçoivent la même communication » = faux : l'engagement se différencie selon pouvoir/intérêt.\n• L'identification des parties prenantes n'est pas un exercice de lancement unique : les réponses « le registre a été fait en phase d'initialisation » signalent le piège.\n• Ne confondez pas satisfaire une partie prenante et céder à sa demande : la demande passe par le processus (changements, backlog), la RELATION se soigne directement.\n• Une partie prenante à fort pouvoir mais faible intérêt ne veut pas être « gérée de près » — l'ensevelir de détails l'agace autant qu'un manque d'information agacerait une partie prenante engagée.\n• Le modèle de saillance (pouvoir, légitimité, urgence) sert à PRIORISER, pas à exclure : une partie prenante faible sur les trois axes reste suivie, simplement avec moins d'effort.",
    en: "• With a resistant stakeholder, “exclude them from meetings” or “ask the sponsor to rein them in” are near-systematic distractors: the right answer starts with UNDERSTANDING their concerns.\n• “All stakeholders get the same communication” = wrong: engagement is differentiated by power/interest.\n• Stakeholder identification is not a one-time kickoff exercise: answers noting “the register was built during initiation” signal the trap.\n• Do not confuse satisfying a stakeholder with yielding to their request: the request goes through process (change control, backlog); the RELATIONSHIP is tended directly.\n• A high-power, low-interest stakeholder does not want to be “managed closely” — burying them in detail annoys them as much as under-informing an engaged stakeholder would.\n• The salience model (power, legitimacy, urgency) is for PRIORITIZING, not excluding: a stakeholder weak on all three axes is still tracked, just with less effort.",
  },
  'pr-value': {
    fr: "• « Le projet a livré dans les délais et le budget » n'est PAS la définition du succès : si le bénéfice n'est pas là, le projet a échoué. Les options centrées sur la triple contrainte seule sont des pièges.\n• Quand le business case est invalidé en cours de route, « continuer parce que c'est contractualisé/déjà payé » est le piège du coût irrécupérable.\n• Le chef de projet n'arrête pas le projet de sa propre autorité : il ALERTE la gouvernance avec des options. Les réponses « arrêter immédiatement » sont excessives.\n• La valeur n'est pas que financière : écarter une option car « le bénéfice n'est pas chiffrable » (conformité, image, apprentissage) est une erreur.\n• Un backlog priorisé uniquement par « facilité technique » (on fait d'abord ce qui est simple) plutôt que par valeur est un piège classique — la facilité guide le SÉQUENÇAGE dans une priorité donnée, jamais la priorité elle-même.\n• Le bénéfice se mesure souvent APRÈS la clôture du projet : une réponse qui déclare le bénéfice « atteint » à la livraison, sans période de mesure, confond extrant (output) et résultat (outcome).",
    en: "• “The project delivered on time and budget” is NOT the definition of success: if the benefit is missing, the project failed. Options centered on the triple constraint alone are traps.\n• When the business case is invalidated mid-flight, “continue because it is contracted/already paid” is the sunk-cost trap.\n• The project manager does not terminate the project on their own authority: they ALERT governance with options. “Stop immediately” answers overreach.\n• Value is not only financial: dismissing an option because “the benefit cannot be quantified” (compliance, brand, learning) is a mistake.\n• A backlog prioritized purely by “technical ease” (do the simple stuff first) rather than value is a classic trap — ease guides SEQUENCING within a given priority, never the priority itself.\n• Benefit is often measured AFTER project closure: an answer declaring the benefit “achieved” at delivery, with no measurement window, confuses output with outcome.",
  },
  'pr-systems': {
    fr: "• Les réponses qui optimisent UN indicateur ou UN composant (accélérer une seule équipe, économiser sur un seul poste) sans regarder l'effet global sont des pièges d'optimisation locale.\n• « Ce changement ne concerne que mon lot » : à l'examen, tout changement significatif appelle une analyse d'impact TRANSVERSE (délai, coût, qualité, risques, personnes).\n• Méfiez-vous des solutions immédiates qui créent un problème en aval plus coûteux (comprimer les tests pour tenir un jalon).\n• Le projet vit dans un portefeuille : une réponse peut être bonne pour le projet et fausse pour l'organisation — l'examen privilégie la vue d'ensemble.\n• Une boucle de rétroaction RENFORÇANTE n'est pas toujours positive : un succès qui attire toujours plus de périmètre sans recalibrer les ressources s'auto-alimente jusqu'à la rupture.\n• « Résoudre le goulot d'étranglement le plus visible » peut être un piège si un autre goulot, moins visible, limite déjà le débit global — l'analyse système cherche la VRAIE contrainte, pas la plus bruyante.",
    en: "• Answers optimizing ONE metric or ONE component (speeding a single team, saving on a single line) without the system-wide effect are local-optimization traps.\n• “This change only affects my work package”: on the exam, any significant change calls for a CROSS-CUTTING impact analysis (schedule, cost, quality, risk, people).\n• Beware immediate fixes that create a costlier downstream problem (squeezing testing to hit a milestone).\n• The project lives in a portfolio: an answer can be right for the project and wrong for the organization — the exam favors the holistic view.\n• A REINFORCING feedback loop is not always positive: a success that keeps attracting more scope without recalibrating resources feeds itself until it breaks.\n• “Fix the most visible bottleneck” can be a trap if another, less visible bottleneck already caps overall throughput — systems analysis looks for the TRUE constraint, not the loudest one.",
  },
  'pr-leadership': {
    fr: "• Le style « command and control » n'est presque jamais la bonne réponse — SAUF urgence réelle (sécurité, crise aiguë) : repérez ce contexte avant d'éliminer l'option directive.\n• « Laisser l'équipe se débrouiller » n'est pas de la délégation, c'est de l'abandon : la délégation garde un cadre et des points de contrôle.\n• Ne confondez pas leadership et autorité : les questions où le chef de projet « n'a pas le pouvoir » testent l'influence (données, relation, négociation), pas l'escalade.\n• Le servant leadership ne signifie pas dire oui à tout : protéger l'équipe inclut de refuser des demandes (heures supplémentaires chroniques, périmètre non arbitré).\n• Le leadership n'est pas réservé au titulaire du poste : une option qui rejette l'initiative d'un membre sous prétexte qu'« il n'est pas chef de projet » ignore que le leadership est un comportement, pas un titre.\n• Un leader qui protège systématiquement son équipe des retours négatifs du client la coupe aussi de l'apprentissage : protéger ≠ isoler de toute réalité inconfortable.",
    en: "• Command-and-control is almost never the right answer — EXCEPT in genuine emergencies (safety, acute crisis): spot that context before eliminating the directive option.\n• “Let the team figure it out” is not delegation, it is abandonment: delegation keeps a frame and checkpoints.\n• Do not confuse leadership with authority: questions where the PM “has no power” test influence (data, relationship, negotiation), not escalation.\n• Servant leadership does not mean saying yes to everything: protecting the team includes refusing demands (chronic overtime, un-arbitrated scope).\n• Leadership is not reserved for the titleholder: an option dismissing a member’s initiative because “they are not the project manager” ignores that leadership is a behavior, not a title.\n• A leader who systematically shields the team from negative customer feedback also cuts it off from learning: protecting ≠ isolating from every uncomfortable reality.",
  },
  'pr-tailoring': {
    fr: "• « Appliquer la méthodologie standard de l'entreprise telle quelle » est un distracteur fréquent : l'examen attend une adaptation JUSTIFIÉE au contexte.\n• L'inverse aussi : « supprimer la gouvernance parce qu'on est agile » est faux — le tailoring se documente et s'assume, il ne s'improvise pas.\n• Prédictif n'est pas synonyme d'obsolète : pour des exigences stables et un coût de changement élevé, c'est LA bonne réponse.\n• Le choix d'approche peut être réévalué en cours de projet : les options qui le figent définitivement (« l'approche a été décidée au lancement ») sont suspectes.\n• Adapter pour « aller plus vite » sans lien avec un facteur réel (taille, criticité, culture, contrainte réglementaire) n'est pas du tailoring, c'est de la négligence déguisée.\n• Deux projets similaires dans la même organisation peuvent légitimement adopter des processus différents : l'uniformité n'est pas une vertu en soi, l'adéquation au contexte l'est.",
    en: "• “Apply the company’s standard methodology as-is” is a frequent distractor: the exam expects a JUSTIFIED adaptation to context.\n• The reverse too: “drop governance because we are agile” is wrong — tailoring is documented and owned, not improvised.\n• Predictive is not obsolete: for stable requirements and a high cost of change, it IS the right answer.\n• The approach can be revisited mid-project: options that freeze it forever (“the approach was decided at kickoff”) are suspect.\n• Tailoring “to go faster” with no link to a real factor (size, criticality, culture, regulatory constraint) is not tailoring, it is negligence in disguise.\n• Two similar projects in the same organization can legitimately adopt different processes: uniformity is not a virtue in itself, fit to context is.",
  },
  'pr-quality': {
    fr: "• Piège n°1 : sacrifier la qualité pour tenir un délai. À l'examen, ce n'est JAMAIS la bonne réponse — on renégocie périmètre, délai ou ressources.\n• Confusion qualité/grade : « produit bas de gamme » ≠ « produit de mauvaise qualité ». Relisez la question avec cette distinction.\n• « Ajouter plus de tests » n'est pas la meilleure réponse quand la PRÉVENTION est disponible : l'inspection coûte plus cher que la conception correcte.\n• Dépasser les exigences « pour faire plaisir » (gold plating) est une FAUTE, pas une qualité : les options généreuses non demandées sont des pièges.\n• Un « % de défauts acceptable » fixé arbitrairement sans lien avec la criticité du produit (dispositif médical vs site vitrine) est un signal d'alerte : la tolérance qualité doit être proportionnée à l'enjeu.\n• « Zéro défaut » n'est pas toujours l'objectif réaliste ni recherché : au-delà d'un certain seuil, le coût marginal de prévention dépasse le coût du défaut résiduel — la qualité s'optimise, elle ne se maximise pas aveuglément.",
    en: "• Trap #1: sacrificing quality to hit a deadline. On the exam this is NEVER the right answer — renegotiate scope, schedule or resources instead.\n• Quality/grade confusion: “low-grade product” ≠ “poor-quality product”. Re-read the question with that distinction.\n• “Add more testing” is not the best answer when PREVENTION is available: inspection costs more than building it right.\n• Exceeding requirements “to please” (gold plating) is a FAULT, not a virtue: generous unrequested options are traps.\n• An arbitrarily set “acceptable defect rate” unrelated to the product’s criticality (medical device vs. showcase website) is a red flag: quality tolerance must match the stakes.\n• “Zero defects” is not always the realistic or sought-after goal: past a certain point, the marginal cost of prevention exceeds the cost of the residual defect — quality is optimized, not blindly maximized.",
  },
  'pr-complexity': {
    fr: "• Face à la complexité, « planifier davantage en détail » est souvent un piège : quand la cause à effet est imprévisible, on EXPÉRIMENTE (spike, prototype, pilote), on ne sur-planifie pas.\n• Ne confondez pas compliqué (analysable par un expert) et complexe (émergent) : la réponse experte convient au premier, l'itération courte au second.\n• « Ajouter des ressources » aggrave souvent la complexité (canaux de communication, loi de Brooks).\n• Les réponses qui promettent d'ÉLIMINER l'incertitude sont fausses : on la réduit et on s'y adapte, on ne la supprime pas.\n• Un problème purement TECHNIQUE (compliqué) traité par un atelier collaboratif de groupe est souvent une perte de temps ; inversement, un problème HUMAIN (complexe) traité par le seul expert technique le plus senior rate sa cible — associez la source de complexité à l'outil adapté.\n• La complexité perçue diminue parfois simplement en DÉCOUPLANT les composants (architecture, équipes), sans changer le contenu du travail lui-même — une option qui ignore le découplage au profit de plus de coordination manque souvent la meilleure réponse.",
    en: "• Facing complexity, “plan in more detail” is often a trap: when cause and effect are unpredictable, you EXPERIMENT (spike, prototype, pilot), you do not over-plan.\n• Do not confuse complicated (expert-analyzable) with complex (emergent): the expert answer fits the former, short iterations fit the latter.\n• “Add resources” often worsens complexity (communication channels, Brooks’s law).\n• Answers promising to ELIMINATE uncertainty are wrong: you reduce and adapt to it, you do not remove it.\n• A purely TECHNICAL (complicated) problem handled through a group collaborative workshop is often wasted effort; conversely, a HUMAN (complex) problem handled by the single most senior technical expert misses the mark — match the source of complexity to the right tool.\n• Perceived complexity sometimes drops simply by DECOUPLING components (architecture, teams), without changing the work’s content itself — an option ignoring decoupling in favor of more coordination often misses the better answer.",
  },
  'pr-risk': {
    fr: "• Un risque IDENTIFIÉ qui se matérialise déclenche le plan de réponse prévu — pas une réunion de crise. Si le plan échoue : plan de repli, puis contournement.\n• Ne confondez pas risque (incertain, futur) et problème/issue (avéré, présent) : « mettre à jour le registre des risques » est faux si l'événement a DÉJÀ eu lieu.\n• Les opportunités sont des risques aussi : une question sur un événement positif attend exploiter/partager/améliorer, pas « atténuer ».\n• La réserve de management n'est pas à la main du chef de projet : « puiser dans la réserve de management » sans approbation est un piège.\n• Accepter un risque N'EST PAS l'ignorer : l'acceptation est documentée, éventuellement avec réserve.\n• La VME (valeur monétaire attendue) d'une menace est NÉGATIVE et celle d'une opportunité POSITIVE : une réponse qui compare des VME sans respecter ce signe inverse la décision.\n• Un risque à forte probabilité mais très faible impact peut légitimement peser MOINS dans la priorisation qu'un risque à faible probabilité mais impact catastrophique — la matrice probabilité-impact évite justement de ne juger que sur un seul axe.",
    en: "• An IDENTIFIED risk that occurs triggers the planned response — not a crisis meeting. If the plan fails: fallback plan, then workaround.\n• Do not confuse a risk (uncertain, future) with an issue (real, present): “update the risk register” is wrong if the event has ALREADY happened.\n• Opportunities are risks too: a question about a positive event expects exploit/share/enhance, not “mitigate”.\n• The management reserve is not the PM’s to spend: “draw on the management reserve” without approval is a trap.\n• Accepting a risk is NOT ignoring it: acceptance is documented, possibly with a reserve.\n• A threat’s EMV (expected monetary value) is NEGATIVE and an opportunity’s is POSITIVE: an answer comparing EMVs without respecting this sign reverses the decision.\n• A high-probability, very-low-impact risk can legitimately rank LOWER in prioritization than a low-probability, catastrophic-impact one — the probability-impact matrix exists precisely to avoid judging on a single axis.",
  },
  'pr-adaptability': {
    fr: "• « Suivre le plan initial coûte que coûte » est un piège quand le contexte a changé : le plan sert les objectifs, pas l'inverse.\n• L'inverse existe aussi : changer d'approche à chaque difficulté sans analyse = zapping. La bonne réponse s'appuie sur des données (rétrospective, tendance) avant de pivoter.\n• Après un choc, les réponses purement défensives (chercher le coupable, geler le projet) perdent face à celles qui rétablissent le service PUIS capitalisent l'apprentissage.\n• Les boucles de feedback courtes ne sont pas réservées à l'agile : même en prédictif, des jalons rapprochés et des revues fréquentes sont la réponse attendue en contexte incertain.\n• La redondance (compétences croisées, fournisseur de secours) a un coût réel — une option qui la maximise partout, sans lien avec la criticité du composant concerné, ignore l'arbitrage coût/résilience.\n• Résilience ne veut pas dire rigidité renforcée : ajouter des contrôles et des approbations après un incident peut RÉDUIRE la capacité d'adaptation au lieu de l'améliorer.",
    en: "• “Stick to the original plan at all costs” is a trap when context has changed: the plan serves the objectives, not the reverse.\n• The reverse exists too: switching approach at every difficulty without analysis = thrashing. The right answer relies on data (retrospective, trend) before pivoting.\n• After a shock, purely defensive answers (find the culprit, freeze the project) lose to those that restore service THEN capture the learning.\n• Short feedback loops are not agile-only: even predictive projects answer uncertainty with closer milestones and frequent reviews.\n• Redundancy (cross-training, backup vendor) has a real cost — an option maximizing it everywhere, unrelated to the component’s criticality, ignores the cost/resilience trade-off.\n• Resiliency does not mean added rigidity: piling on controls and approvals after an incident can REDUCE adaptive capacity instead of improving it.",
  },
  'pr-change': {
    fr: "• Ne confondez pas conduite du changement (adoption par les personnes) et maîtrise des changements (processus de modification des références) : deux notions, deux familles de réponses.\n• La résistance se DIAGNOSTIQUE avant de se traiter : « communiquer plus » sans comprendre la cause est un pansement — cherchez l'option qui écoute d'abord.\n• Imposer le changement par la hiérarchie (« la direction l'a décidé ») est un distracteur récurrent : l'adoption ne se décrète pas.\n• Le changement se prépare PENDANT le projet, pas après la livraison : les options qui repoussent la formation/communication « à la mise en service » sont trop tardives.\n• Un plan de changement qui ne prévoit pas de date d'EXTINCTION de l'ancien processus laisse cohabiter les deux indéfiniment : les utilisateurs reviennent naturellement à l'ancien par confort, pas par malveillance.\n• Le changement organisationnel n'est pas terminé au go-live : un renforcement post-lancement (accompagnement, mesure d'adoption) fait autant partie du plan que la préparation en amont.",
    en: "• Do not confuse change management (people adoption) and change control (baseline modification process): two notions, two answer families.\n• Resistance is DIAGNOSED before being treated: “communicate more” without understanding the cause is a band-aid — look for the option that listens first.\n• Imposing change through hierarchy (“leadership decided”) is a recurring distractor: adoption cannot be decreed.\n• Change is prepared DURING the project, not after delivery: options deferring training/communication “to go-live” are too late.\n• A change plan with no SUNSET date for the old process lets both coexist indefinitely: users naturally drift back to the old one out of comfort, not malice.\n• Organizational change is not done at go-live: post-launch reinforcement (support, adoption measurement) is as much part of the plan as upfront preparation.",
  },

  // ──────────────────────── PERFORMANCE DOMAINS ────────────────────────
  'pd-stakeholders': {
    fr: "• L'ordre des opérations compte : identifier → analyser → planifier l'engagement → agir. Une réponse qui « engage » une partie prenante non analysée saute une étape.\n• La matrice d'engagement compare état ACTUEL et état SOUHAITÉ : les options qui n'utilisent qu'une colonne passent à côté.\n• Une partie prenante mineure aujourd'hui peut devenir critique demain (réorganisation, nouveau régulateur) : « le registre est déjà fait » est un signal de piège.\n• Communiquer PLUS n'est pas communiquer MIEUX : le bon canal et le bon format (push/pull/interactif) priment sur la fréquence.\n• Un tableau d'engagement rempli une seule fois puis jamais mis à jour équivaut à ne pas en avoir : l'examen valorise la RÉÉVALUATION périodique, pas la simple existence du document.\n• Deux parties prenantes en désaccord ouvert ne se départagent pas en choisissant la plus « haut placée » : on cherche l'alignement sur les objectifs et la valeur du projet, indépendamment de la hiérarchie.",
    en: "• Order of operations matters: identify → analyze → plan engagement → act. An answer that “engages” an un-analyzed stakeholder skips a step.\n• The engagement matrix compares CURRENT vs DESIRED state: options using only one column miss the point.\n• A minor stakeholder today can be critical tomorrow (reorg, new regulator): “the register is already done” signals a trap.\n• Communicating MORE is not communicating BETTER: right channel and format (push/pull/interactive) beat frequency.\n• An engagement matrix filled in once and never updated is as good as not having one: the exam values periodic REASSESSMENT, not the document’s mere existence.\n• Two openly disagreeing stakeholders are not settled by picking the more senior one: the resolution seeks alignment with project objectives and value, independent of hierarchy.",
  },
  'pd-team': {
    fr: "• Tout changement de composition fait RÉGRESSER l'équipe dans le modèle de Tuckman : les réponses qui supposent une équipe « performing pour toujours » sont fausses.\n• En storming, le chef de projet FACILITE activement — ni laisser-faire (« ça passera »), ni recomposition immédiate.\n• Augmenter le salaire ne motive pas durablement (Herzberg) : quand l'option « prime/augmentation » côtoie « reconnaissance/responsabilité », la seconde gagne.\n• Le conflit se traite TÔT, en PRIVÉ, entre les intéressés : toute option publique ou différée perd des points.\n• Une équipe virtuelle n'a pas besoin des MÊMES rituels qu'une équipe co-localisée simplement transposés en visio : l'inclusion exige d'adapter réellement le format (horaires tournants, décisions asynchrones documentées).\n• Le fait qu'une équipe soit « senior » ne dispense pas de charte d'équipe ni de règles explicites — l'expérience individuelle ne remplace pas des accords COLLECTIFS négociés.",
    en: "• Any composition change REGRESSES the team on Tuckman’s ladder: answers assuming a “forever performing” team are wrong.\n• In storming, the PM actively FACILITATES — neither laissez-faire (“it will pass”) nor instant restructuring.\n• Raising pay does not durably motivate (Herzberg): when “bonus/raise” sits next to “recognition/responsibility”, the latter wins.\n• Conflict is addressed EARLY, in PRIVATE, with those involved: any public or deferred option loses.\n• A virtual team does not need the SAME rituals as a co-located one merely moved to video calls: inclusion requires genuinely adapting the format (rotating hours, documented async decisions).\n• A team being “senior” does not exempt it from a team charter or explicit ground rules — individual experience does not replace negotiated COLLECTIVE agreements.",
  },
  'pd-approach': {
    fr: "• Le critère de choix n'est pas la mode mais le CONTEXTE : volatilité des exigences, coût du changement tardif, besoin de feedback. Une réponse « agile parce que moderne » est un piège.\n• Hybride ne veut pas dire flou : chaque composante garde SON mécanisme (CCB côté prédictif, re-priorisation backlog côté agile) — coordonnés, pas fusionnés.\n• Itératif (raffiner) ≠ incrémental (additionner) : l'examen teste cette distinction avec des scénarios concrets.\n• Un contrat forfaitaire ou une contrainte réglementaire n'interdit pas l'agile, mais le CONTRAINT : cherchez les réponses nuancées (agile sous contrainte documentaire), pas binaires.\n• Le cycle de vie choisi au lancement n'est pas gravé dans le marbre : un projet qui découvre en cours de route que ses exigences sont devenues volatiles peut légitimement basculer vers plus d'itératif, avec une décision explicite et documentée.\n• « Le client ne connaît pas l'agile » n'est pas une raison suffisante pour imposer le prédictif si le contexte technique justifie l'agile — c'est un signal d'accompagnement du changement à prévoir, pas un critère de choix de cycle de vie.",
    en: "• The selection criterion is not fashion but CONTEXT: requirements volatility, cost of late change, feedback need. “Agile because modern” is a trap.\n• Hybrid does not mean fuzzy: each component keeps ITS mechanism (CCB on the predictive side, backlog reprioritization on the agile side) — coordinated, not merged.\n• Iterative (refine) ≠ incremental (add): the exam tests this distinction with concrete scenarios.\n• A fixed-price contract or regulation does not forbid agile, it CONSTRAINS it: look for nuanced answers (agile under documentation constraints), not binary ones.\n• The life cycle chosen at kickoff is not set in stone: a project discovering mid-course that its requirements turned volatile can legitimately shift toward more iterative work, with an explicit, documented decision.\n• “The customer does not know agile” is not sufficient reason to impose predictive if the technical context justifies agile — it is a signal to plan change support, not a life-cycle selection criterion.",
  },
  'pd-planning': {
    fr: "• « Planifier une fois pour toutes » et « ne rien planifier car agile » sont les deux pièges symétriques : l'élaboration est PROGRESSIVE dans les deux mondes.\n• Toute modification d'une référence de base passe par la maîtrise des changements — même « un petit ajustement d'une semaine ».\n• Détailler finement le travail lointain fabrique de la fausse précision : la planification par vagues est la réponse attendue.\n• Les estimations appartiennent à CEUX QUI FONT le travail : une option où le management impose les chiffres est un signal d'alarme.\n• Un plan « juste suffisant » n'est pas un plan minimal par paresse : il documente ce qui est nécessaire pour coordonner et s'engager, ni plus (bureaucratie), ni moins (chaos).\n• En agile, « pas de plan détaillé au départ » ne veut pas dire absence de planification : feuille de route produit, plan de release et planification de sprint constituent une hiérarchie de plans à part entière.",
    en: "• “Plan once and for all” and “no planning because agile” are symmetric traps: elaboration is PROGRESSIVE in both worlds.\n• Any baseline modification goes through change control — even “a small one-week adjustment”.\n• Finely detailing distant work manufactures false precision: rolling wave planning is the expected answer.\n• Estimates belong to THOSE WHO DO the work: an option where management imposes the numbers is a red flag.\n• A “just enough” plan is not a minimal plan out of laziness: it documents what is needed to coordinate and commit — no more (bureaucracy), no less (chaos).\n• In agile, “no detailed plan upfront” does not mean no planning: product roadmap, release plan and sprint planning form a full planning hierarchy of their own.",
  },
  'pd-work': {
    fr: "• Les leçons apprises se capturent EN CONTINU : « faire l'atelier leçons apprises à la clôture » est le piège standard.\n• Sur les contrats, associez réflexe et type : FFP = risque fournisseur (et rigidité en cas de changement) ; coûts remboursables = risque acheteur (et besoin de surveillance) ; T&M = périmètre flou, courte durée.\n• « Envoyer un courriel » n'est pas gérer la communication : pour un sujet sensible ou urgent, l'interactif s'impose.\n• Un problème fournisseur se traite d'abord par le DIALOGUE et les mécanismes contractuels prévus — la résiliation ou l'arrêt des paiements sans processus exposent à des réclamations.\n• Passer d'une équipe de 8 à 11 personnes n'ajoute pas « 3 relations » mais 25 nouveaux canaux (n(n−1)/2) : une réponse qui sous-estime ce saut de complexité de communication rate le calcul.\n• Un audit de conformité contractuelle n'est pas un signe de défiance envers le fournisseur : c'est une clause normale du contrat, à distinguer d'une inspection punitive.",
    en: "• Lessons learned are captured CONTINUOUSLY: “hold the lessons-learned workshop at closure” is the standard trap.\n• On contracts, pair reflex with type: FFP = seller risk (and rigidity under change); cost-reimbursable = buyer risk (and monitoring burden); T&M = fuzzy scope, short duration.\n• “Send an email” is not managing communication: for sensitive or urgent topics, interactive is required.\n• A vendor problem is first handled through DIALOGUE and the contract’s built-in mechanisms — termination or payment withholding without process invites claims.\n• Growing a team from 8 to 11 does not add “3 relationships” but 25 new channels (n(n−1)/2): an answer underestimating this communication-complexity jump misses the math.\n• A contractual compliance audit is not a sign of distrust toward the vendor: it is a normal contract clause, distinct from a punitive inspection.",
  },
  'pd-delivery': {
    fr: "• DoD ≠ critères d'acceptation : la DoD est GÉNÉRIQUE (tout élément), les critères sont SPÉCIFIQUES (un élément). Les questions jouent sur cette confusion.\n• Assouplir la DoD pour « tenir la vélocité » fabrique de la dette invisible : toujours faux.\n• Du travail non demandé mais « utile » reste du gold plating tant que le propriétaire de la valeur n'a pas arbitré.\n• La dérive de périmètre vient rarement d'une grosse demande : ce sont les « petits ajouts raisonnables » non tracés qui la constituent — le processus s'applique aussi à eux.\n• « Le client a accepté verbalement » ne vaut pas acceptation formelle : l'absence de documentation écrite expose à des litiges ultérieurs sur ce qui a réellement été livré.\n• Livrer une fonctionnalité « à 90 % terminée » n'apporte aucune valeur mesurable : dans une logique incrémentale, seul un incrément RÉELLEMENT terminé (au sens de la DoD) compte comme valeur livrée.",
    en: "• DoD ≠ acceptance criteria: the DoD is GENERIC (every item), criteria are SPECIFIC (one item). Questions play on this confusion.\n• Relaxing the DoD to “protect velocity” manufactures invisible debt: always wrong.\n• Unrequested but “useful” work remains gold plating until the value owner arbitrates.\n• Scope creep rarely comes from one big request: it is the untracked “small reasonable additions” — the process applies to them too.\n• “The customer verbally agreed” is not formal acceptance: lacking written documentation exposes the project to later disputes over what was actually delivered.\n• Delivering a feature “90% done” provides no measurable value: under an incremental logic, only a TRULY done increment (per the DoD) counts as delivered value.",
  },
  'pd-measurement': {
    fr: "• Un indicateur devenu OBJECTIF cesse d'être fiable (loi de Goodhart) : compter les anomalies fermées, comparer les vélocités entre équipes… repérez l'effet pervers dans les options.\n• SPI/CPI > 1 = bon, < 1 = mauvais — mais un SPI de 1,0 en fin de projet peut cacher un chemin critique en retard (le SPI converge vers 1 mécaniquement).\n• « % d'avancement déclaré » est invérifiable : préférez les règles objectives (0/100, jalons vérifiables).\n• Mesurer l'EFFORT (heures) n'est pas mesurer le RÉSULTAT : les options « suivre les heures passées » répondent rarement à la question posée.\n• Un tableau de bord entièrement vert alors que l'équipe signale des difficultés en aparté est un symptôme de reporting pastèque : la réponse attendue traite la cause (sécurité psychologique), pas le format du rapport.\n• Comparer le CPI de deux projets de nature très différente (taille, secteur, maturité de l'équipe) sans contexte conduit à de fausses conclusions : un indice de performance se lit dans SA propre trajectoire, pas en absolu contre un autre projet.",
    en: "• A metric turned TARGET stops being reliable (Goodhart’s law): counting closed defects, comparing velocities across teams… spot the perverse incentive among the options.\n• SPI/CPI > 1 = good, < 1 = bad — but an SPI of 1.0 late in the project can hide a late critical path (SPI mechanically converges to 1).\n• “Declared % complete” is unverifiable: prefer objective earning rules (0/100, verifiable milestones).\n• Measuring EFFORT (hours) is not measuring OUTCOME: “track hours spent” options rarely answer the question asked.\n• An all-green dashboard while the team privately reports struggles is a watermelon-reporting symptom: the expected answer treats the cause (psychological safety), not the report’s format.\n• Comparing the CPI of two very different projects (size, industry, team maturity) with no context leads to false conclusions: a performance index is read against ITS OWN trajectory, not in absolute terms against another project.",
  },
  'pd-uncertainty': {
    fr: "• Réserve pour aléas (risques identifiés, DANS la référence de base, à la main du chef de projet) ≠ réserve de management (imprévus, HORS référence, approbation requise) : distinction testée en boucle.\n• Risque ≠ ambiguïté ≠ volatilité : analyser plus ne réduit pas une ambiguïté — expérimenter, si.\n• Un registre de risques « tous verts depuis six mois » n'est pas rassurant, c'est un processus MORT.\n• Le risque global du projet n'est pas la somme des risques individuels : une question sur l'exposition d'ENSEMBLE attend une réponse de niveau portefeuille/gouvernance.\n• Une incertitude non traitée n'équivaut PAS forcément à un risque négatif : dans certains cas, elle recouvre une opportunité non identifiée — l'attitude proactive cherche des deux côtés, pas seulement les menaces.\n• Vouloir « tout quantifier avant d'agir » sous forte incertitude est souvent un piège paralysant : parfois, l'action la moins coûteuse consiste à générer de l'information (spike, prototype) plutôt qu'à analyser indéfiniment.",
    en: "• Contingency reserve (identified risks, INSIDE the baseline, PM-controlled) ≠ management reserve (unknowns, OUTSIDE the baseline, approval required): tested repeatedly.\n• Risk ≠ ambiguity ≠ volatility: more analysis does not reduce ambiguity — experimentation does.\n• A risk register “all green for six months” is not reassuring, it is a DEAD process.\n• Overall project risk is not the sum of individual risks: a question about AGGREGATE exposure expects a portfolio/governance-level answer.\n• Untreated uncertainty does NOT necessarily equal negative risk: in some cases it hides an unidentified opportunity — the proactive stance searches both sides, not just threats.\n• Wanting to “quantify everything before acting” under heavy uncertainty is often a paralyzing trap: sometimes the cheapest action is generating information (spike, prototype) rather than analyzing indefinitely.",
  },

  // ─────────────────────────── EXAM TOPICS ───────────────────────────
  'tp-eco': {
    fr: "• La moitié des questions est en contexte agile/hybride, mais la répartition People/Process/Business reste la grille : ne cherchez pas un « domaine agile ».\n• Les questions demandent la MEILLEURE action, pas une action correcte : deux options peuvent être vraies, une seule est la plus juste (souvent la plus en amont : comprendre, analyser).\n• « EN PREMIER », « ENSUITE », « MEILLEURE » : ces mots changent la réponse. Les relire est la compétence n°1.\n• Le temps est un piège en soi : ~76 s/question. Marquez et passez plutôt que de vous enliser — c'est aussi ce que ce simulateur entraîne.\n• Une question multi-réponse (« sélectionnez DEUX/TROIS ») ne donne AUCUN point si la sélection est incomplète ou comporte une option en trop : ne validez qu'une fois le nombre exact atteint.\n• Se souvenir de son ressenti sur une question difficile après l'avoir marquée coûte plus cher que d'avancer : le stress cumulé sur une question bloquée dégrade la performance sur les suivantes — marquer et passer est une compétence de gestion du temps, pas un aveu d'échec.",
    en: "• Half the questions are agile/hybrid, but People/Process/Business remains the grid: do not look for an “agile domain”.\n• Questions ask for the BEST action, not a correct one: two options can be true, only one is most right (usually the most upstream: understand, analyze).\n• “FIRST”, “NEXT”, “BEST”: these words change the answer. Re-reading them is skill #1.\n• Time itself is a trap: ~76 s/question. Flag and move on rather than sink — which this simulator trains too.\n• A multi-response question (“select TWO/THREE”) earns ZERO points for an incomplete or over-full selection: only submit once the exact count is reached.\n• Dwelling on a hard question after flagging it costs more than moving on: accumulated stress on a stuck question degrades performance on the following ones — flagging and moving is a time-management skill, not an admission of failure.",
  },
  'tp-evm': {
    fr: "• EAC = BAC/CPI seulement si l'écart est TYPIQUE ; s'il est ponctuel, EAC = AC + (BAC − EV). Repérez « atypique / ne se reproduira pas » dans l'énoncé.\n• SV/CV : toujours EV en premier (EV − PV, EV − AC). Négatif = mauvais. Une inversion mentale coûte la question.\n• SV en fin de projet tend vers 0 même si le projet a été en retard : ne concluez pas « à l'heure » sur cette seule base.\n• TCPI > 1 signifie qu'il faut faire MIEUX que prévu sur le restant : comparez-le au CPI actuel pour juger le réalisme — c'est souvent la vraie question posée.\n• ETC ≠ EAC : ETC est le coût du travail RESTANT (EAC − AC), EAC est le coût TOTAL prévu du projet. Confondre les deux dans un calcul en chaîne fait dériver toutes les réponses suivantes.\n• VAC = BAC − EAC : un VAC négatif signale un dépassement prévu, pas un dépassement déjà survenu — c'est une PROJECTION, à ne pas confondre avec CV (l'écart déjà constaté).",
    en: "• EAC = BAC/CPI only if the variance is TYPICAL; if one-off, EAC = AC + (BAC − EV). Spot “atypical / will not recur” in the stem.\n• SV/CV: EV always first (EV − PV, EV − AC). Negative = bad. A mental swap costs the question.\n• SV tends to 0 at project end even if the project ran late: do not conclude “on time” from that alone.\n• TCPI > 1 means doing BETTER than planned on the remainder: compare it to the current CPI to judge realism — often the real question being asked.\n• ETC ≠ EAC: ETC is the cost of the REMAINING work (EAC − AC), EAC is the TOTAL projected project cost. Confusing the two in a chained calculation derails every following answer.\n• VAC = BAC − EAC: a negative VAC signals a projected overrun, not an overrun that already happened — it is a FORECAST, not to be confused with CV (the variance already observed).",
  },
  'tp-agile': {
    fr: "• Le Product Owner arbitre la VALEUR (contenu, priorités) ; le Scrum Master facilite le PROCESSUS ; l'équipe décide du COMMENT. Attribuer une décision au mauvais rôle est le piège agile n°1.\n• Le daily n'est pas un reporting au chef de projet ; la revue porte sur le PRODUIT, la rétrospective sur le PROCESSUS.\n• Mid-sprint, une urgence réelle se NÉGOCIE avec le PO (échange de contenu) — le sprint ne s'annule que si son objectif est obsolète.\n• La vélocité n'est ni un engagement contractuel ni un outil de comparaison entre équipes.\n• En Kanban, les limites de WIP ne sont pas des objectifs à maximiser : les dépasser régulièrement (« on a de la marge ») signale une mauvaise lecture de l'outil, pas une performance.\n• Une classe de service « expedite » sans limite explicite de capacité (souvent 1 seul créneau) finit par absorber tout le flux normal — la vraie discipline Kanban borne même les urgences.",
    en: "• The Product Owner arbitrates VALUE (content, priorities); the Scrum Master facilitates the PROCESS; the team decides the HOW. Assigning a decision to the wrong role is agile trap #1.\n• The daily is not a status report to the PM; the review is about the PRODUCT, the retrospective about the PROCESS.\n• Mid-sprint, a genuine emergency is NEGOTIATED with the PO (content swap) — the sprint is cancelled only if its goal is obsolete.\n• Velocity is neither a contractual commitment nor a cross-team comparison tool.\n• In Kanban, WIP limits are not targets to maximize: regularly exceeding them (“we have headroom”) signals a misreading of the tool, not good performance.\n• An “expedite” class of service with no explicit capacity limit (often just 1 slot) ends up absorbing all normal flow — real Kanban discipline bounds even emergencies.",
  },
  'tp-conflict': {
    fr: "• Collaborer est LA réponse préférée, mais pas l'unique : forcer devient correct en urgence réelle (sécurité) ; éviter peut l'être temporairement quand les émotions débordent. Lisez le contexte.\n• Compromis n'est pas collaboration : « couper la poire en deux » perd face à « explorer les intérêts sous-jacents ».\n• Le conflit appartient d'abord aux intéressés : les options où le chef de projet tranche immédiatement ou escalade d'emblée sautent des étapes.\n• Confronter le PROBLÈME, jamais la PERSONNE : une option qui blâme quelqu'un publiquement est éliminatoire, quel que soit son réalisme.\n• « Aplanir » (smoothing) n'est pas de la lâcheté : c'est un choix délibéré pour préserver une relation à court terme, tant qu'on prévoit d'y revenir sur le fond plus tard — l'utiliser comme solution DÉFINITIVE est en revanche un piège.\n• Deux options « collaborer » peuvent apparaître : celle qui adresse la cause RACINE du désaccord bat celle qui ne traite que le symptôme immédiat, même si les deux relèvent techniquement de la collaboration.",
    en: "• Collaborating is THE preferred answer, but not the only one: forcing becomes correct in a real emergency (safety); avoiding can be right temporarily when emotions overflow. Read the context.\n• Compromise is not collaboration: “split the difference” loses to “explore the underlying interests”.\n• The conflict belongs first to those involved: options where the PM immediately decides or escalates skip steps.\n• Confront the PROBLEM, never the PERSON: an option that publicly blames someone is disqualifying, however realistic.\n• “Smoothing” is not cowardice: it is a deliberate choice to preserve a relationship short-term, provided you plan to revisit the substance later — using it as a PERMANENT fix, however, is a trap.\n• Two “collaborate” options can appear: the one addressing the ROOT cause of the disagreement beats the one treating only the immediate symptom, even though both are technically collaboration.",
  },
  'tp-change': {
    fr: "• Le réflexe absolu : ÉVALUER L'IMPACT avant d'approuver, refuser, implémenter ou escalader. Toute option qui agit avant d'analyser est fausse.\n• Le chef de projet n'approuve pas lui-même un changement de référence de base : c'est le rôle du CCB / de l'autorité définie dans le plan.\n• Une demande REJETÉE se consigne aussi (journal des changements) — « classer sans suite » est un piège.\n• En agile, le « changement » passe par la re-priorisation du backlog par le PO, pas par un CCB — sauf sur la partie prédictive d'un projet hybride.\n• L'urgence n'abolit pas le processus : un correctif d'urgence suit la procédure accélérée PRÉVUE, puis est documenté a posteriori.\n• Une action corrective (remettre le projet sur SA trajectoire déjà approuvée) suit un circuit plus léger qu'un vrai changement de périmètre — les confondre fait choisir un processus disproportionné dans un sens ou dans l'autre.\n• « Le changement est petit » n'est jamais un motif suffisant pour le sauter : c'est l'IMPACT évalué, pas la taille apparente de la demande, qui détermine le niveau de traitement.",
    en: "• The absolute reflex: ASSESS THE IMPACT before approving, rejecting, implementing or escalating. Any option that acts before analyzing is wrong.\n• The PM does not personally approve a baseline change: that is the CCB’s / the plan-designated authority’s role.\n• A REJECTED request is logged too (change log) — “file and forget” is a trap.\n• In agile, “change” flows through PO backlog reprioritization, not a CCB — except on the predictive part of a hybrid project.\n• Urgency does not abolish process: an emergency fix follows the DEFINED expedited procedure, then is documented after the fact.\n• A corrective action (returning the project to ITS already-approved trajectory) follows a lighter path than a true scope change — confusing the two picks a disproportionate process either way.\n• “The change is small” is never sufficient reason to skip it: it is the assessed IMPACT, not the request’s apparent size, that determines the level of handling.",
  },
  'tp-risk': {
    fr: "• Apprenez les DEUX familles de réponses : menaces (éviter/transférer/atténuer/accepter/escalader) et opportunités (exploiter/partager/améliorer/accepter/escalader). L'examen adore présenter une opportunité et proposer « atténuer ».\n• Transférer ne supprime pas le risque : l'assurance déplace l'impact FINANCIER, le risque opérationnel demeure (et crée souvent un risque secondaire).\n• Risque secondaire (créé par la réponse) ≠ risque résiduel (ce qui reste après la réponse).\n• Escalader est une VRAIE stratégie : quand le risque dépasse le périmètre ou l'autorité du projet, c'est la bonne réponse — pas un aveu d'échec.\n• Un plan de réponse aux risques qui n'a jamais été TESTÉ (répétition, revue) n'est qu'une hypothèse sur le papier : au moment critique, il peut échouer autant qu'une absence de plan.\n• La même menace peut appeler des réponses différentes selon l'appétence au risque de l'organisation : ce qui est « accepter » pour une organisation tolérante peut être « atténuer » ou « transférer » pour une organisation prudente — le contexte de gouvernance fait partie de la réponse.",
    en: "• Learn BOTH answer families: threats (avoid/transfer/mitigate/accept/escalate) and opportunities (exploit/share/enhance/accept/escalate). The exam loves presenting an opportunity and offering “mitigate”.\n• Transferring does not remove the risk: insurance moves the FINANCIAL impact; the operational risk remains (and often spawns a secondary risk).\n• Secondary risk (created by the response) ≠ residual risk (what remains after the response).\n• Escalating is a REAL strategy: when the risk exceeds the project’s scope or authority, it is the right answer — not an admission of failure.\n• A risk response plan never TESTED (rehearsed, reviewed) is just a hypothesis on paper: at the critical moment, it can fail as much as having no plan at all.\n• The same threat can call for different responses depending on the organization’s risk appetite: what is “accept” for a risk-tolerant organization can be “mitigate” or “transfer” for a cautious one — the governance context is part of the answer.",
  },
  'tp-schedule': {
    fr: "• On ne compresse JAMAIS une activité hors chemin critique : elle a déjà de la marge, la raccourcir ne change pas la date de fin.\n• Crashing = coût ↑ ; fast tracking = risque ↑. Si l'énoncé interdit tout surcoût → fast tracking ; s'il interdit tout risque de reprise → crashing.\n• Après chaque compression, RECALCULER : un autre chemin peut devenir critique.\n• Marge totale (protège la FIN du projet) ≠ marge libre (protège le SUCCESSEUR) : les énoncés qui donnent les deux valeurs testent cette différence.\n• Nivellement (contrainte de ressources, peut allonger le projet) ≠ lissage (dans les marges, ne change pas la fin).\n• Sur un réseau à chemins multiples convergents, le chemin critique est TOUJOURS le plus long en durée — jamais celui qui semble le plus risqué ou le plus coûteux si sa durée n'est pas la plus longue.\n• Une dépendance obligatoire (contrainte physique, ex. couler les fondations avant les murs) ne peut PAS être fast-trackée aussi facilement qu'une dépendance discrétionnaire (choix de méthode) : toutes les liaisons ne se compressent pas de la même manière.",
    en: "• NEVER crash an activity off the critical path: it already has float; shortening it does not move the finish date.\n• Crashing = cost ↑; fast tracking = risk ↑. If the stem forbids extra cost → fast track; if it forbids rework risk → crash.\n• After each compression, RECALCULATE: another path may become critical.\n• Total float (protects the project FINISH) ≠ free float (protects the SUCCESSOR): stems giving both values test this difference.\n• Leveling (resource constraint, may extend the project) ≠ smoothing (within float, finish unchanged).\n• On a network with multiple converging paths, the critical path is ALWAYS the longest in duration — never the one that merely looks riskiest or costliest if its duration is not the longest.\n• A mandatory dependency (physical constraint, e.g., pour the foundation before the walls) cannot be fast-tracked as easily as a discretionary one (a method choice): not all links compress the same way.",
  },
  'tp-pmbok8': {
    fr: "• Le retour des processus dans le PMBOK® 8 ne réhabilite pas la réponse « suivre la procédure mécaniquement » : face à deux options, celle qui sert un PRINCIPE (valeur, intendance, engagement) bat celle qui récite une étape.\n• Ne perdez pas de temps à mémoriser des numéros de processus : l'examen teste le raisonnement, pas la table des matières.\n• Les questions ne mentionnent jamais « PMBOK 7 » ou « PMBOK 8 » : elles testent des situations. Le référentiel est un outil de préparation, pas un contenu à réciter.\n• Si une option cite un document/processus très précis et l'autre un comportement de bon sens aligné sur les principes, le comportement gagne le plus souvent.\n• Les 12 principes ne sont pas hiérarchisés entre eux : à situation identique, ce n'est jamais « le principe X prime toujours sur Y » — c'est le CONTEXTE de la question qui indique lequel est le plus pertinent.\n• Un scénario qui semble tout droit sorti d'un référentiel prédictif « ancienne école » (processus rigides, contrôle strict) n'est pas automatiquement faux : dans un contexte fortement réglementé, cette rigueur PEUT être la réponse alignée sur les principes.",
    en: "• The return of processes in PMBOK® 8 does not rehabilitate “follow the procedure mechanically”: between two options, the one serving a PRINCIPLE (value, stewardship, engagement) beats the one reciting a step.\n• Do not memorize process numbers: the exam tests reasoning, not the table of contents.\n• Questions never mention “PMBOK 7” or “PMBOK 8”: they test situations. The guide is a preparation tool, not content to recite.\n• When one option cites a very specific document/process and another describes principle-aligned good judgment, the behavior usually wins.\n• The 12 principles are not ranked against each other: for a given situation, it is never “principle X always beats Y” — the question’s CONTEXT indicates which is most relevant.\n• A scenario that looks straight out of an “old-school” predictive playbook (rigid processes, tight control) is not automatically wrong: in a heavily regulated context, that rigor CAN be the principle-aligned answer.",
  },
}
